import pika
import subprocess
import shlex
import os

def callback(ch, method, properties, body):
    command = body.decode('utf-8')
    try:
        # Use shlex to safely split the command into arguments
        args = shlex.split(command)
        # Execute the command
        result = subprocess.run(args, check=True, capture_output=True)
        print(f"Command executed successfully: {result.stdout.decode()}")
    except subprocess.CalledProcessError as e:
        print(f"Error executing command: {e.stderr.decode()}")

def main():
    # Set up RabbitMQ connection
    connection = pika.BlockingConnection(pika.ConnectionParameters(host='localhost'))
    channel = connection.channel()

    # Declare the queue
    channel.queue_declare(queue='job_queue')

    # Set up the consumer
    channel.basic_consume(queue='job_queue', on_message_callback=callback, auto_ack=True)

    print('Waiting for messages. To exit press CTRL+C')
    channel.start_consuming()

if __name__ == '__main__':
    main()